import os
import pandas as pd

season_ep = {"pilot": "s01e01"}
errors = []
# os.walk yields (root, dirs, files). `dirs` is a list, not a path.
for dirs, files in [(["dir1"], ["show-pilot.mp4"])]:
    for name in files:
        try:
            to_print = season_ep[name.split('-')[-1][:-4]]
            print(to_print)
        except KeyError:
            errors.append(os.path.join(dirs, name))  # TypeError: dirs is a list
